SELECT
summary_id,
company_id,
template_id,
start_date,
end_date,
language,
input_hash,
health_level,
summary_json,
generated_at,
generated_by
FROM survey_ai_summaries
WHERE company_id = #{companyId}
AND (
(#{templateId,jdbcType=VARCHAR} IS NULL AND template_id IS NULL)
OR template_id = #{templateId,jdbcType=VARCHAR}
)
AND (
(#{startDate,jdbcType=DATE} IS NULL AND start_date IS NULL)
OR start_date = #{startDate,jdbcType=DATE}
)
AND (
(#{endDate,jdbcType=DATE} IS NULL AND end_date IS NULL)
OR end_date = #{endDate,jdbcType=DATE}
)
AND language = #{language}
AND input_hash = #{inputHash}
ORDER BY generated_at DESC
LIMIT 1

SELECT COUNT(1)
FROM survey_ai_summaries
WHERE company_id = #{companyId}
AND generated_by = #{generatedBy}
AND generated_at >= #{since}
